const deviceId = msg.topic.split('/')[1];
const status = (typeof msg.payload === 'object') ? msg.payload.status : String(msg.payload);
msg.headers = {
  'Content-Type': 'application/json',
  'Prefer': 'resolution=merge-duplicates',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY')
};
msg.method = 'POST';
msg.url = env.get('SUPABASE_REST') + '/devices?on_conflict=device_id';
msg.payload = [{ device_id: deviceId, status, last_seen: new Date().toISOString() }];
return msg;

const deviceId = msg.topic.split('/')[1];
let data = msg.payload;
if (typeof data !== 'object') { try { data = JSON.parse(data); } catch(e) { data = { value: data }; } }
msg.headers = {
  'Content-Type': 'application/json',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY')
};
msg.method = 'POST';
msg.url = env.get('SUPABASE_REST') + '/telemetry';
msg.payload = [{ device_id: deviceId, data, recorded_at: new Date().toISOString() }];
return msg;
